WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")} 

var conrecord = sforce.connection.query("SELECT id,Email from Contact  where id ='{!Contact.Id}'" );

records = conrecord.getArray("records"); 

var email = records[0].Email; 

if(email!=null)
{
var sendemail = confirm('A Working Hours Breach Letter used for drivers whose weekly Working Hours have exceeded 60 hours will be sent to the candidate.  Do you want to continue?');
if(sendemail == true)
{
var flag = sforce.apex.execute("CandidateBreachletter","sendcandidateemail",{conID:"{! 
Contact.Id}"}); 
if(flag == 'true')
{
alert('Email sent successfully');
window.location.reload(); 
}
else
{
alert('Error occured in sending email. Your admin has been notified with the details');
window.location.reload(); 
}
}
else
{
window.location.reload(); 
}
}
else{
alert('Candidate does not have an Email ID');
window.location.reload();  
}
